import java.util.*; public class Solution { public static long run(List<String> rows) { long hash = 1469598103934665603L; for (String row : rows) { String[] parts = row.split("&"); int u = Integer.parseInt(parts[0].substring(2)); int s = Integer.parseInt(parts[1].substring(6)); int f = Integer.parseInt(parts[2].substring(5)); long v = (u & 2047) + s + f * 19L; hash ^= (v + 1); hash *= 1099511628211L; } return hash; } }